import re
import keyword


def create_module_docstring(name, desc, author, version):
    return f"'''{name}\n\n{desc}\n\nAuthor: {author}\nVersion: {version}\n'''"


def validate_module_name(name):
    if not name or not isinstance(name, str):
        return False
    if name != name.lower():
        return False
    if keyword.iskeyword(name):
        return False
    return bool(re.match(r'^[a-z_][a-z0-9_]*$', name))


def extract_public_api(code_text):
    names = []
    for line in code_text.splitlines():
        # Only consider top-level lines (not indented)
        if line and not line[0].isspace():
            match_def = re.match(r'^def\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*\(', line)
            match_class = re.match(r'^class\s+([a-zA-Z_][a-zA-Z0-9_]*)[\s(:]', line)
            match_var = re.match(r'^([a-zA-Z_][a-zA-Z0-9_]*)\s*=', line)
            for m in [match_def, match_class, match_var]:
                if m:
                    name = m.group(1)
                    if not name.startswith('_'):
                        names.append(name)
                    break
    return sorted(set(names))


def generate_init_file(modules_list):
    lines = []
    for mod in modules_list:
        lines.append(f'from .{mod} import *')
    lines.append('')
    all_items = ', '.join(f"'{mod}'" for mod in modules_list)
    lines.append(f'__all__ = [{all_items}]')
    lines.append('')
    return '\n'.join(lines)
